// MARK: - Transaction Processor
class TransactionProcessor {
    static let shared = TransactionProcessor()
    private var transactions: [Transaction] = []
    private var accounts: [Account] = []
    
    private init() {
        loadStoredData()
    }
    
    func processTransaction(_ transaction: Transaction) -> Bool {
        guard let account = accounts.first else { return false }
        
        switch transaction.type {
        case .debit:
            if account.balance >= transaction.amount {
                accounts[0].balance -= transaction.amount
                transactions.append(transaction)
                saveData()
                return true
            }
        case .credit:
            accounts[0].balance += transaction.amount
            transactions.append(transaction)
            saveData()
            return true
        }
        return false
    }
    
    func getAccountBalance() -> Double {
        return accounts.first?.balance ?? 0.0
    }
    
    func getTransactionHistory() -> [Transaction] {
        return transactions
    }
    
    func addAccount(_ account: Account) {
        accounts.append(account)
        saveData()
    }
    
    private func saveData() {
        if let data = try? JSONEncoder().encode(accounts),
           let transactionsData = try? JSONEncoder().encode(transactions) {
            let key = "secure_bank_data_key"
            if let encryptedAccountData = SecureDataHandler.shared.encryptData(data, withKey: key),
               let encryptedTransactionData = SecureDataHandler.shared.encryptData(transactionsData, withKey: key) {
                UserDefaults.standard.set(encryptedAccountData, forKey: "encrypted_accounts")
                UserDefaults.standard.set(encryptedTransactionData, forKey: "encrypted_transactions")
            }
        }
    }
    
    private func loadStoredData() {
        let key = "secure_bank_data_key"
        if let encryptedAccounts = UserDefaults.standard.data(forKey: "encrypted_accounts"),
           let encryptedTransactions = UserDefaults.standard.data(forKey: "encrypted_transactions"),
           let accountsData = SecureDataHandler.shared.decryptData(encryptedAccounts, withKey: key),
           let transactionsData = SecureDataHandler.shared.decryptData(encryptedTransactions, withKey: key) {
            if let accounts = try? JSONDecoder().decode([Account].self, from: accountsData) {
                self.accounts = accounts
            }
            if let transactions = try? JSONDecoder().decode([Transaction].self, from: transactionsData) {
                self.transactions = transactions
            }
        }
    }
}

// MARK: - Secure Extension
extension Data {
    func aes256Encrypt(withKey key: Data) -> Data? {
        guard key.count == 32 else { return nil }
        
        let cryptOptions = CCOptions(kCCOptionECBMode + kCCOptionPKCS7Padding)
        var encryptedData = Data(repeating: 0, count: self.count + kCCBlockSizeAES128)
        var encryptedLength = encryptedData.count
        
        let status = self.withUnsafeBytes { (selfBytes: UnsafeRawBufferPointer) in
            key.withUnsafeBytes { (keyBytes: UnsafeRawBufferPointer) in
                CCCrypt(CCOperation(kCCEncrypt),
                        CCAlgorithm(kCCAlgorithmAES),
                        cryptOptions,
                        keyBytes.baseAddress,
                        key.count,
                        nil,
                        selfBytes.baseAddress,
                        self.count,
                        &encryptedData,
                        encryptedLength,
                        &encryptedLength)
            }
        }
        
        return status == kCCSuccess ? Data(encryptedData[0..<encryptedLength]) : nil
    }
    
    func aes256Decrypt(withKey key: Data) -> Data? {
        guard key.count == 32 else { return nil }
        
        let cryptOptions = CCOptions(kCCOptionECBMode + kCCOptionPKCS7Padding)
        var decryptedData = Data(repeating: 0, count: self.count + kCCBlockSizeAES128)
        var decryptedLength = decryptedData.count
        
        let status = self.withUnsafeBytes { (selfBytes: UnsafeRawBufferPointer) in
            key.withUnsafeBytes { (keyBytes: UnsafeRawBufferPointer) in
                CCCrypt(CCOperation(kCCDecrypt),
                        CCAlgorithm(kCCAlgorithmAES),
                        cryptOptions,
                        keyBytes.baseAddress,
                        key.count,
                        nil,
                        selfBytes.baseAddress,
                        self.count,
                        &decryptedData,
                        decryptedLength,
                        &decryptedLength)
            }
        }
        
        return status == kCCSuccess ? Data(decryptedData[0..<decryptedLength]) : nil
    }
}

// MARK: - Bank Service
class BankService {
    static let shared = BankService()
    
    private init() {}
    
    func performTransfer(amount: Double, to recipient: String) -> Bool {
        let transaction = Transaction(
            id: UUID().uuidString,
            amount: amount,
            type: .debit,
            date: Date(),
            description: "Transfer to \(recipient)",
            recipient: recipient
        )
        
        return TransactionProcessor.shared.processTransaction(transaction)
    }
    
    func getAccountBalance() -> Double {
        return TransactionProcessor.shared.getAccountBalance()
    }
    
    func getTransactionHistory() -> [Transaction] {
        return TransactionProcessor.shared.getTransactionHistory()
    }
    
    func createAccount(accountNumber: String, balance: Double) {
        let account = Account(
            id: UUID().uuidString,
            accountNumber: accountNumber,
            balance: balance,
            currency: "USD",
            accountType: "Checking",
            ownerName: "User",
            createdDate: Date()
        )
        
        TransactionProcessor.shared.addAccount(account)
    }
}

