class TransactionViewModel: ObservableObject {
    @Published var amount: String = ""
    @Published var recipient: String = ""
    @Published var errorMessage: String?
    
    func processTransfer() {
        guard let amountValue = Double(amount), !recipient.isEmpty else {
            errorMessage = "Please enter valid amount and recipient"
            return
        }
        
        let success = BankService.shared.performTransfer(amount: amountValue, to: recipient)
        if !success {
            errorMessage = "Transfer failed. Insufficient balance."
        } else {
            errorMessage = nil
            amount = ""
            recipient = ""
        }
    }
}